<?php
if (session_status() === PHP_SESSION_NONE) {
    session_start();
}

require_once __DIR__ . '/../../../lessons/core/db.php';
if (!function_exists('get_pdo')) die('Error: get_pdo() was not found.');

function qz_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function qz_json($v){if($v===null||$v==='')return[];if(is_array($v))return$v;$d=json_decode((string)$v,true);return is_array($d)?$d:[];}
function qz_norm($v){return strtolower(trim(preg_replace('/\s+/',' ',(string)$v)));}
function qz_pick($r,$keys,$def=''){foreach($keys as $k){if(isset($r[$k])&&trim((string)$r[$k])!=='')return$r[$k];}return$def;}
function qz_redirect($m,$u,$a,$q=null,$x=[]){$url='?mode='.urlencode($m).'&unit='.intval($u).'&assignment='.intval($a);if($q!==null)$url.='&q='.intval($q);foreach($x as$k=>$v)$url.='&'.urlencode($k).'='.urlencode((string)$v);header('Location: '.$url);exit;}
function qz_rows_from_data($data){$p=qz_json($data);$rows=[];if(!$p)return$rows;if(isset($p[0])&&is_array($p[0]))$rows=$p;foreach(['questions','items','data','words','sentences','pairs','lines']as$k){if(isset($p[$k])&&is_array($p[$k])){$rows=$p[$k];break;}}if(empty($rows)&&is_array($p))$rows=[$p];return$rows;}
function qz_is_scoreable_type($type){return in_array($type,['quiz','multiple_choice','video_comprehension','fillblank','fill_blank','fill_in_blank','writing_practice','question_answer','matching_lines','match','dictation','pronunciation','order_sentences','unscramble','listen_order','drag_drop','drag_drop_kids'],true);}
function qz_add_mc(&$out,$id,$question,$options,$correct,$image=''){$options=array_values(array_filter($options,fn($v)=>trim((string)$v)!==''));if(trim((string)$question)!==''&&count($options)>=2)$out[]=['id'=>$id,'type'=>'multiple_choice','question'=>$question,'options'=>$options,'correct'=>$correct,'audio'=>'','image'=>$image,'pairs'=>[]];}
function qz_add_fill(&$out,$id,$question,$answer){if(trim((string)$question)!==''&&trim((string)$answer)!=='')$out[]=['id'=>$id,'type'=>'fill','question'=>$question,'options'=>[],'correct'=>$answer,'audio'=>'','image'=>'','pairs'=>[]];}
function qz_add_match(&$out,$id,$pairs,$question='Match each item with the correct option.'){$clean=[];foreach($pairs as$p){if(!is_array($p))continue;$l=qz_pick($p,['left','term','word','en','front','question','a','from']);$r=qz_pick($p,['right','match','translation','es','back','answer','b','to']);if($l!==''&&$r!=='')$clean[]=['left'=>$l,'right'=>$r];}if(count($clean)>=2)$out[]=['id'=>$id,'type'=>'match','question'=>$question,'options'=>[],'correct'=>'','audio'=>'','image'=>'','pairs'=>$clean];}
function qz_add_dict(&$out,$id,$row){$text=qz_pick($row,['en','sentence','word','text','answer','correct','expected']);$audio=qz_pick($row,['audio','audio_url','file','media'],'');if($text!=='')$out[]=['id'=>$id,'type'=>'dictation','question'=>'Listen carefully and write what you hear.','options'=>[],'correct'=>$text,'audio'=>$audio,'image'=>'','pairs'=>[]];}
function qz_add_pron(&$out,$id,$row){$word=qz_pick($row,['en','word','text','phrase','prompt','question']);$img=qz_pick($row,['img','image','image_url']);$audio=qz_pick($row,['audio','audio_url']);if($word!=='')$out[]=['id'=>$id,'type'=>'pronunciation','question'=>'Pronounce or identify the correct word/phrase.','options'=>[],'correct'=>$word,'audio'=>$audio,'image'=>$img,'pairs'=>[]];}
function qz_normalize_activity($act){$type=strtolower(trim((string)($act['type']??'')));if(!qz_is_scoreable_type($type))return[];$rows=qz_rows_from_data($act['data']??null);$out=[];$base=(string)($act['id']??uniqid('qz_',true));
 if($type==='quiz'||$type==='multiple_choice'||$type==='video_comprehension'){foreach($rows as$i=>$r){if(!is_array($r))continue;$opts=[];if(isset($r['options'])&&is_array($r['options']))$opts=$r['options'];elseif(isset($r['choices'])&&is_array($r['choices']))$opts=$r['choices'];else $opts=[$r['option_a']??'',$r['option_b']??'',$r['option_c']??'',$r['option_d']??''];qz_add_mc($out,$base.'_'.$i,qz_pick($r,['question','prompt','text','title']),$opts,qz_pick($r,['correct','correct_answer','answer','expected'],0),qz_pick($r,['img','image','image_url']));}}
 elseif($type==='fillblank'||$type==='fill_blank'||$type==='fill_in_blank'||$type==='writing_practice'||$type==='question_answer'){foreach($rows as$i=>$r){if(!is_array($r))continue;$q=qz_pick($r,['question','prompt','sentence','text','en']);$a=qz_pick($r,['answer','correct','correct_answer','expected','es']);qz_add_fill($out,$base.'_'.$i,$q,$a);}}
 elseif($type==='matching_lines'||$type==='match'||$type==='listen_order'||$type==='drag_drop'||$type==='drag_drop_kids'){qz_add_match($out,$base.'_m',$rows,'Match each item with its correct pair.');}
 elseif($type==='dictation'){foreach($rows as$i=>$r)if(is_array($r))qz_add_dict($out,$base.'_'.$i,$r);}
 elseif($type==='pronunciation'){foreach($rows as$i=>$r)if(is_array($r))qz_add_pron($out,$base.'_'.$i,$r);}
 elseif($type==='order_sentences'||$type==='unscramble'){foreach($rows as$i=>$r){if(!is_array($r))continue;$sentence=qz_pick($r,['sentence','text','en','answer','correct']);if($sentence!=='')qz_add_fill($out,$base.'_'.$i,'Write the sentence in the correct order.',$sentence);}}
 return$out;}
function qz_target_count($n,$ratio=.75,$min=5,$max=15){if($n<=0)return 0;if($n===1)return 1;$t=(int)floor($n*$ratio);return min($n,max($min,min($max,$t)));}
function qz_seed($u,$a,$att){$k='qz_seed_'.md5($u.'_'.$a.'_'.$att);if(!isset($_SESSION[$k]))$_SESSION[$k]=random_int(100000,999999);return(int)$_SESSION[$k];}
function qz_shuffle(&$arr,$seed){mt_srand($seed);for($i=count($arr)-1;$i>0;$i--){$j=mt_rand(0,$i);[$arr[$i],$arr[$j]]=[$arr[$j],$arr[$i]];}mt_srand();}
function qz_build($all,$u,$a,$att){$by=[];foreach($all as$q)$by[$q['type']][]=$q;$seed=qz_seed($u,$a,$att);foreach($by as$t=>&$l){qz_shuffle($l,$seed+crc32($t));$l=array_slice($l,0,6);}unset($l);$target=qz_target_count(array_sum(array_map('count',$by)));$final=[];$pool=[];foreach($by as$l){if(!$l)continue;$final[]=array_shift($l);foreach($l as$q)$pool[]=$q;}qz_shuffle($pool,$seed+77);$final=array_merge($final,array_slice($pool,0,max(0,$target-count($final))));qz_shuffle($final,$seed+99);return$final;}
function qz_correct($q,$a){if($a===null||$a==='')return false;if($q['type']==='match'){if(!is_array($a))return false;foreach($q['pairs']as$i=>$p)if(!isset($a[$i])||(string)$a[$i]!== (string)$p['right'])return false;return true;}if($q['type']==='multiple_choice'){if(is_numeric($q['correct']))return(string)$a===(string)$q['correct'];$opts=$q['options'];return isset($opts[(int)$a])&&qz_norm($opts[(int)$a])===qz_norm($q['correct']);}return qz_norm($a)===qz_norm($q['correct']);}
$unitId=isset($_GET['unit'])?intval($_GET['unit']):0;$assignment=isset($_GET['assignment'])?intval($_GET['assignment']):0;$mode=$_GET['mode']??(isset($_GET['step'])&&intval($_GET['step'])>0?'quiz':'intro');$qIndex=isset($_GET['q'])?intval($_GET['q']):0;if(!$unitId)die('Missing unit id.');
$pdo=get_pdo();$st=$pdo->prepare('SELECT * FROM activities WHERE unit_id=:u ORDER BY id ASC');$st->execute(['u'=>$unitId]);$activities=$st->fetchAll(PDO::FETCH_ASSOC);$all=[];foreach($activities as$act)foreach(qz_normalize_activity($act)as$q)$all[]=$q;if(!$all){echo'<div style="font-family:Arial;padding:30px;color:#7c3aed"><h2>No scoreable quiz activities found for this unit.</h2><p>Debug: activities found: '.count($activities).'</p><ul>';foreach($activities as$a)echo'<li>id '.qz_h($a['id']??'').' type <b>'.qz_h($a['type']??'').'</b> scoreable: '.(qz_is_scoreable_type(strtolower((string)($a['type']??'')))?'yes':'no').' data preview: '.qz_h(substr((string)($a['data']??''),0,220)).'</li>';echo'</ul></div>';exit;}
$attKey='qz_attempt_'.$unitId.'_'.$assignment;if(!isset($_SESSION[$attKey]))$_SESSION[$attKey]=1;$att=(int)$_SESSION[$attKey];$setKey='qz_set_'.$unitId.'_'.$assignment.'_'.$att;$ansKey='qz_answers_'.$unitId.'_'.$assignment.'_'.$att;if(isset($_GET['reset'])){$_SESSION[$attKey]=$att+1;unset($_SESSION[$setKey],$_SESSION[$ansKey]);qz_redirect('intro',$unitId,$assignment);}if(!isset($_SESSION[$setKey]))$_SESSION[$setKey]=qz_build($all,$unitId,$assignment,$att);if(!isset($_SESSION[$ansKey]))$_SESSION[$ansKey]=[];$quiz=$_SESSION[$setKey];$answers=&$_SESSION[$ansKey];$total=count($quiz);
if($_SERVER['REQUEST_METHOD']==='POST'&&$mode==='quiz'){$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];if(isset($_POST['skip'])){$answers[$qIndex]=['answer'=>null,'skipped'=>true,'correct'=>false];$n=$qIndex+1;qz_redirect($n>=$total?'result':'quiz',$unitId,$assignment,$n>=$total?null:$n);}$ans=$q['type']==='match'?(isset($_POST['answer'])&&is_array($_POST['answer'])?$_POST['answer']:[]):($_POST['answer']??'');$ok=qz_correct($q,$ans);$answers[$qIndex]=['answer'=>$ans,'skipped'=>false,'correct'=>$ok];qz_redirect('quiz',$unitId,$assignment,$qIndex,['feedback'=>1]);}
$labels=['multiple_choice'=>['Multiple choice','Pick the correct answer','ti-checks'],'fill'=>['Fill in the blank','Complete the sentence','ti-pencil'],'match'=>['Match pairs','Connect each word to its pair','ti-arrows-shuffle'],'dictation'=>['Dictation','Listen and write what you hear','ti-volume'],'pronunciation'=>['Pronunciation','Say the phrase','ti-microphone']];$counts=[];foreach($quiz as$q)$counts[$q['type']]=($counts[$q['type']]??0)+1;$correct=0;$skip=0;foreach($answers as$a){if(!empty($a['correct']))$correct++;if(!empty($a['skipped']))$skip++;}$wrong=max(0,count($answers)-$correct-$skip);$percent=$total?round($correct/$total*100):0;
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Unit Quiz</title><link href="https://fonts.googleapis.com/css2?family=Fredoka:wght@500;600;700&family=Nunito:wght@500;600;700;800&display=swap" rel="stylesheet"><link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css"><style>:root{--pu:#8070dd;--or:#ff7315;--ink:#14113a;--mut:#8f86c5;--line:#e9e3fb;--bg:#f8f7ff}*{box-sizing:border-box}body{margin:0;background:var(--bg);font-family:Nunito,sans-serif;color:var(--ink)}.page{max-width:720px;margin:auto;padding:28px 16px 48px}.top,.card{background:white;border:1px solid var(--line);border-radius:18px}.top{padding:14px 22px;display:flex;justify-content:space-between;max-width:520px;margin:0 auto 22px}.brand{font-weight:900;color:var(--pu)}.sub{font-size:13px;color:var(--mut)}.tabs{display:flex;gap:8px;justify-content:center;flex-wrap:wrap;margin-bottom:16px}.tab{border:1px solid var(--line);background:white;color:var(--mut);border-radius:999px;padding:7px 13px;font-size:12px;font-weight:900}.tab.on{background:var(--pu);color:white}.screen-title{text-align:center;color:#c0b8e8;font-size:12px;font-weight:900;letter-spacing:.08em;text-transform:uppercase;margin-bottom:12px}.card{max-width:440px;margin:auto;padding:24px}.kicker{display:inline-block;background:#fff0e6;color:var(--or);border:1px solid #ffd1ad;border-radius:999px;padding:5px 13px;font-weight:900;font-size:12px}.title{font:700 29px Fredoka,sans-serif;color:var(--or);margin:10px 0 4px}.lead{color:var(--pu);font-size:14px}.chips{display:flex;gap:8px;flex-wrap:wrap;margin:18px 0}.chip{border:1px solid var(--line);border-radius:999px;color:var(--pu);padding:7px 12px;font-size:12px;font-weight:900;background:#fbfaff}.hr{height:1px;background:var(--line);margin:18px 0}.included{color:#a99ee0;font-size:12px;font-weight:900}.type-row{display:flex;gap:12px;align-items:center;background:#f6f3ff;border-radius:12px;padding:12px;margin:8px 0}.type-row i{color:var(--pu);font-size:20px}.type-row span:last-child{margin-left:auto;color:var(--pu);font-weight:900}.btn{border:0;border-radius:10px;padding:13px 16px;font-weight:900;cursor:pointer;text-decoration:none;display:inline-flex;align-items:center;justify-content:center;gap:6px}.btn-primary{background:var(--or);color:white}.btn-purple{background:var(--pu);color:white}.btn-light{background:white;color:var(--pu);border:1px solid var(--line)}.w100{width:100%}.progress-head{display:flex;justify-content:space-between;color:var(--pu);font-size:12px;font-weight:900}.track{height:7px;background:#eeeafa;border-radius:999px;overflow:hidden;margin:8px 0 18px}.bar{height:100%;background:linear-gradient(90deg,var(--or),var(--pu))}.tag{display:inline-flex;gap:6px;align-items:center;background:#f0ecff;color:var(--pu);border-radius:999px;padding:6px 10px;font-size:12px;font-weight:900;text-transform:uppercase;margin-bottom:12px}.question{font-weight:900;line-height:1.35;margin-bottom:16px}.option{border:1px solid var(--line);border-radius:10px;padding:12px;margin-bottom:8px;display:flex;gap:12px;font-weight:800;font-size:14px}.option input{display:none}.letter{background:#eeeafa;color:var(--pu);border-radius:999px;width:24px;height:24px;display:inline-flex;align-items:center;justify-content:center}.option:has(input:checked){border-color:var(--pu);background:#f8f6ff}.feedback{border-radius:10px;padding:12px;margin:12px 0;font-size:13px;font-weight:900}.good{background:#eafff3;border:1px solid #9af0bf;color:#07823f}.bad{background:#fff0f0;border:1px solid #ffb4b4;color:#c82020}.input,.select{width:100%;border:1px solid var(--line);border-radius:10px;padding:13px;font:800 14px Nunito;margin-bottom:10px}.match-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}.match-left{padding:11px;border:1px solid var(--pu);border-radius:9px;text-align:center;font-weight:900;background:#fbfaff}.actions{display:flex;gap:8px;margin-top:14px}.result-hero{background:linear-gradient(135deg,#eee9ff,#fff0e6);border-radius:14px;text-align:center;padding:28px 16px;margin-bottom:18px}.pct{font:700 44px Fredoka,sans-serif;color:var(--or)}.pill{display:inline-flex;border-radius:999px;padding:5px 10px;font-size:12px;font-weight:900;margin:4px}.review{border:1px solid var(--line);border-radius:12px;padding:12px;margin-bottom:10px}.media-box{height:120px;border-radius:12px;background:#f3f0ff;display:flex;align-items:center;justify-content:center;color:#cbc4ed;font-size:38px;margin-bottom:12px}</style></head><body><div class="page"><div class="top"><div><div class="brand">Quiz de Unidad – Mockup</div><div class="sub">inglésdeuna · <?php echo$total;?> preguntas dinámicas</div></div></div><div class="tabs"><?php foreach(['intro'=>'Intro','quiz'=>'Quiz','fill'=>'Fill in blank','match'=>'Match','dictation'=>'Dictation','pronunciation'=>'Pronunciation','result'=>'Resultado','review'=>'Review']as$m=>$lab):?><button class="tab <?php echo($mode===$m||($mode==='quiz'&&isset($quiz[$qIndex])&&$quiz[$qIndex]['type']===$m))?'on':'';?>"><?php echo qz_h($lab);?></button><?php endforeach;?></div>
<?php if($mode==='intro'):?><div class="screen-title">Pantalla 1 — Portada del quiz</div><div class="card"><span class="kicker">UNIT <?php echo$unitId;?> · QUIZ</span><div class="title">Unit Quiz</div><div class="lead">Answer all questions to complete this unit and unlock the next one.</div><div class="chips"><span class="chip"><?php echo$total;?> questions</span><span class="chip">~8 min</span><span class="chip">3 attempts</span></div><div class="hr"></div><div class="included">WHAT'S INCLUDED</div><?php foreach($counts as$t=>$c):$inf=$labels[$t]??[$t,'','ti-circle'];?><div class="type-row"><i class="ti <?php echo qz_h($inf[2]);?>"></i><div><b><?php echo qz_h($inf[0]);?></b><small style="display:block;color:var(--mut)"><?php echo qz_h($inf[1]);?></small></div><span><?php echo$c;?></span></div><?php endforeach;?><div class="hr"></div><a class="btn btn-purple w100" href="?mode=quiz&q=0&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Start quiz</a></div>
<?php elseif($mode==='quiz'):$qIndex=max(0,min($qIndex,$total-1));$q=$quiz[$qIndex];$inf=$labels[$q['type']]??[$q['type'],'','ti-circle'];$fb=isset($_GET['feedback'])&&isset($answers[$qIndex]);$ok=$answers[$qIndex]['correct']??false;?><div class="screen-title">Pregunta <?php echo$qIndex+1;?> — <?php echo qz_h($inf[0]);?></div><div class="card"><div class="progress-head"><span>PROGRESS</span><span><?php echo$qIndex+1;?> / <?php echo$total;?></span></div><div class="track"><div class="bar" style="width:<?php echo round((($qIndex+1)/$total)*100);?>%"></div></div><div class="tag"><i class="ti <?php echo qz_h($inf[2]);?>"></i><?php echo qz_h($inf[0]);?></div><?php if($q['image']):?><img src="<?php echo qz_h($q['image']);?>" style="width:100%;height:150px;object-fit:contain" class="media-box"><?php endif;?><div class="question"><?php echo qz_h($q['question']);?></div><?php if($q['audio']):?><audio controls src="<?php echo qz_h($q['audio']);?>" style="width:100%;margin-bottom:12px"></audio><?php endif;?><?php if($fb):?><div class="feedback <?php echo$ok?'good':'bad';?>"><?php echo$ok?'Correct! Well done.':'Not quite. Correct answer: '.qz_h($q['type']==='match'?'See review':$q['correct']);?></div><a class="btn btn-primary w100" href="?mode=<?php echo$qIndex+1>=$total?'result':'quiz';?>&q=<?php echo$qIndex+1;?>&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Next question →</a><?php else:?><form method="post"><?php if($q['type']==='multiple_choice'):foreach($q['options']as$i=>$opt):?><label class="option"><input type="radio" name="answer" value="<?php echo$i;?>" required><span class="letter"><?php echo chr(65+$i);?></span><?php echo qz_h($opt);?></label><?php endforeach;?><?php elseif($q['type']==='match'):?><div class="match-grid"><?php foreach($q['pairs']as$i=>$p):?><div class="match-left"><?php echo qz_h($p['left']);?></div><select class="select" name="answer[<?php echo$i;?>]" required><option value="">Select</option><?php foreach($q['pairs']as$p2):?><option value="<?php echo qz_h($p2['right']);?>"><?php echo qz_h($p2['right']);?></option><?php endforeach;?></select><?php endforeach;?></div><?php else:?><input class="input" name="answer" required placeholder="Type your answer"><?php endif;?><div class="actions"><button class="btn btn-light" name="skip" value="1" formnovalidate>Skip</button><button class="btn btn-primary w100">Check answer →</button></div></form><?php endif;?></div>
<?php elseif($mode==='result'):?><div class="screen-title">Pantalla 7 — Resultado final</div><div class="card"><div class="result-hero"><h2 style="color:var(--pu)">Quiz complete!</h2><div class="pct"><?php echo$percent;?>%</div><div class="sub"><?php echo$correct;?> out of <?php echo$total;?> correct</div><span class="pill good"><?php echo$correct;?> correct</span><span class="pill bad"><?php echo$wrong;?> wrong</span><span class="pill"><?php echo$skip;?> skipped</span></div><div class="actions"><a class="btn btn-light w100" href="?mode=review&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">See review</a><a class="btn btn-primary w100" href="../hub/?unit=<?php echo$unitId;?>">Back to unit →</a></div><a class="btn btn-purple w100" style="margin-top:12px" href="?reset=1&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Try again</a></div>
<?php elseif($mode==='review'):?><div class="screen-title">Pantalla 8 — Review</div><div class="card"><div class="title">Review</div><?php foreach($quiz as$i=>$q):$a=$answers[$i]??['correct'=>false];?><div class="review"><b><?php echo($i+1).'. '.qz_h($q['question']);?></b><br><small><?php echo!empty($a['correct'])?'Correct':'Incorrect/skipped';?></small><div class="sub">Correct: <?php echo qz_h($q['type']==='match'?json_encode(array_column($q['pairs'],'right')):$q['correct']);?></div></div><?php endforeach;?><a class="btn btn-purple w100" href="?mode=result&unit=<?php echo$unitId;?>&assignment=<?php echo$assignment;?>">Back to results</a></div><?php endif;?></div></body></html>
